module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
// TODO: Your implementation here
// Note: You may use `assign` statement in this module.
always @(*) begin
    // Initialize the quotient and remainder
    result = 0;
    odd = 0;
    // Extract the higher 8 bits of the dividend
    reg [7:0] remainder;
    remainder = A[15:8];
    // Compare the remainder with the divisor
    reg [7:0] divisor;
    divisor = B;
    reg [7:0] quotient;
    quotient = 0;
    integer i;
    for (i = 0; i < 8; i = i + 1) begin
        if (remainder >= divisor) begin
            quotient[i] = 1;
            remainder = remainder - divisor;
        end
        remainder = remainder << 1;
        remainder[0] = A[7 - i];
        divisor = divisor >> 1;
    end
    // Assign the computed quotient and remainder to the output ports
    result = {8'b0, quotient};
    odd = {8'b0, remainder};
end
endmodule
